const body = $json.body ?? $json;

if (!body.event) throw new Error('event is required');
if (!body.city) throw new Error('city is required');
if (!body.date) throw new Error('date is required');
if (!body.time) throw new Error('time is required');
if (body.participants === undefined || body.participants === null) {
  throw new Error('participants is required');
}

const preferences = Array.isArray(body.preferences)
  ? body.preferences.map((value) => String(value).trim()).filter(Boolean)
  : [];

const budget = body.budget && typeof body.budget === 'object'
  ? {
      type: body.budget.type === 'per_person' ? 'per_person' : 'total',
      amount: Number(body.budget.amount ?? 0),
      currency: body.budget.currency || 'RUB'
    }
  : {
      type: 'total',
      amount: 0,
      currency: 'RUB'
    };

return {
  json: {
    event: String(body.event).trim(),
    city: String(body.city).trim(),
    date: String(body.date).trim(),
    time: String(body.time).trim(),
    budget,
    participants: Number(body.participants),
    preferences
  }
};

const data = $json;

const prefs = Array.isArray(data.preferences) ? data.preferences : [];
const sourceText = [data.event, ...prefs].join(' ').toLowerCase();

const unique = (values) => [...new Set(values.filter(Boolean))];
const has = (re) => re.test(sourceText);

const housingTerms = [];
const occasionTerms = [];
const featureTerms = [];

if (has(/дом|домик|коттедж|шале|вилл|гостев(ой)?\s*дом/iu)) {
  housingTerms.push('коттедж', 'гостевой дом', 'дом отдыха');
}
if (has(/база|турбаза|база\s*отдыха|глэмпинг/iu)) {
  housingTerms.push('база отдыха', 'турбаза', 'глэмпинг');
}
if (has(/день\s*рождения|юбилей|праздник/iu)) {
  occasionTerms.push('день рождения');
}
if (has(/мангал|барбекю|шашлык/iu)) {
  featureTerms.push('мангал', 'барбекю', 'беседка');
}
if (has(/баня|сауна/iu)) {
  featureTerms.push('баня', 'сауна');
}

if (housingTerms.length === 0 && has(/корпоратив|команда|тимбилдинг/iu)) {
  housingTerms.push('база отдыха');
}
if (housingTerms.length === 0 && occasionTerms.length > 0) {
  housingTerms.push('коттедж', 'база отдыха');
}
if (occasionTerms.length === 0 && !has(/свадьба|корпоратив|конференц/iu)) {
  occasionTerms.push(data.event);
}

const budgetType = data.budget?.type || 'total';
const budgetAmount = Number(data.budget?.amount || 0);
const participants = Math.max(Number(data.participants || 1), 1);
const budgetPerPerson = budgetType === 'per_person' ? budgetAmount : Math.floor(budgetAmount / participants);

const queryTerms = unique([
  ...housingTerms,
  ...occasionTerms,
  ...featureTerms,
  ...prefs.slice(0, 2)
]);

const query2gis = [data.city, ...queryTerms].join(' ').replace(/\s+/g, ' ').trim();

return [
  {
    json: {
      ...data,
      budget_per_person: budgetPerPerson,
      housing_terms: unique(housingTerms),
      occasion_terms: unique(occasionTerms),
      feature_terms: unique(featureTerms),
      query_2gis: query2gis || data.city,
      city_normalized: String(data.city || '').trim().toLowerCase()
    }
  }
];

const input = $('Code in JavaScript2').first().json;
const items = Array.isArray($json.result?.items) ? $json.result.items : [];

const normalize = (value) => String(value ?? '').toLowerCase().trim();
const toText = (value) => {
  const text = String(value ?? '').trim();
  return text === '' ? null : text;
};
const unique = (values) => [...new Set(values.filter(Boolean))];

const weekdays = [
  ['Mon', 'Пн'],
  ['Tue', 'Вт'],
  ['Wed', 'Ср'],
  ['Thu', 'Чт'],
  ['Fri', 'Пт'],
  ['Sat', 'Сб'],
  ['Sun', 'Вс']
];

const rubricNames = (item) => Array.isArray(item.rubrics)
  ? item.rubrics.map((rubric) => String(rubric?.name || '').trim()).filter(Boolean)
  : [];

const rubricText = (item) => rubricNames(item).map(normalize).join(' ');

const formatSchedule = (schedule) => {
  if (!schedule || typeof schedule !== 'object') return null;
  if (schedule.is_24x7) return 'Круглосуточно';

  const parts = [];
  for (const [key, label] of weekdays) {
    const day = schedule[key];
    const ranges = Array.isArray(day?.working_hours)
      ? day.working_hours
          .map((slot) => {
            const from = String(slot?.from || '').trim();
            const to = String(slot?.to || '').trim();
            return from && to ? `${from}-${to}` : null;
          })
          .filter(Boolean)
      : [];

    if (ranges.length > 0) {
      parts.push(`${label} ${ranges.join(', ')}`);
    }
  }

  const comment = toText(schedule.comment);
  return toText([...parts, comment].filter(Boolean).join('; '));
};

const extractImageUrl = (item) => {
  const external = item.external_content;
  if (external && typeof external === 'object') {
    if (Array.isArray(external.photos) && external.photos.length > 0) {
      return toText(external.photos[0]?.url || external.photos[0]?.preview_url);
    }
    return toText(external.main_photo_url || external.photo_url);
  }
  return null;
};

const extractDescription = (item) => {
  return toText(
    item.description || [item.purpose_name, item.address_comment, ...rubricNames(item).slice(0, 3)].filter(Boolean).join(' • ')
  );
};

const extractRating = (item) => {
  const rating = Number(item.reviews?.general_rating);
  return Number.isFinite(rating) && rating > 0 ? Number(rating.toFixed(2)) : null;
};

const extractAvgBill = (item) => {
  const groups = Array.isArray(item.attribute_groups) ? item.attribute_groups : [];
  for (const group of groups) {
    const attributes = Array.isArray(group?.attributes) ? group.attributes : [];
    for (const attribute of attributes) {
      const text = toText(attribute?.name || attribute?.value || attribute?.text);
      const tag = normalize(attribute?.tag);
      if (text && /(средн|avg|average).*(чек|bill|price)|^(от )?\d+[ ₽р]/iu.test(text)) {
        return text;
      }
      if (text && tag.includes('avg_bill')) {
        return text;
      }
    }
  }
  return null;
};

const extractCuisine = (item) => {
  const names = rubricNames(item);
  const cuisines = names.filter((name) => /кухн|grill|барбекю|пицц|суши|азиат|кавказ|грузин|итальян|европ|япон|узбек|корей|стейк|бург/i.test(name));
  return toText(unique(cuisines).join(', '));
};

const extractContacts = (item) => {
  const groups = Array.isArray(item.contact_groups) ? item.contact_groups : [];
  const contacts = [];
  for (const group of groups) {
    for (const contact of Array.isArray(group?.contacts) ? group.contacts : []) {
      const text = toText(contact?.text || contact?.value || contact?.url || contact?.print_text);
      if (text) contacts.push(text);
    }
  }
  return toText(unique(contacts).join(', '));
};

const ranked = items
  .filter((item) => item && item.type === 'branch')
  .map((item) => {
    const name = toText(item.name);
    const address = toText(item.full_name || item.address_name);
    const text = [
      item.name,
      item.full_name,
      item.address_name,
      item.address_comment,
      item.purpose_name,
      item.description,
      item.type,
      rubricText(item)
    ].map(normalize).join(' ');

    let score = 0;
    if (/аренда коттеджей|коттедж|домик|дом\s*отдыха|гостев(ой)?\s*дом|шале|вилл/iu.test(text)) score += 14;
    if (/база\s*отдыха|турбаза|глэмпинг/iu.test(text)) score += 10;
    if (/банкет|мероприяти|праздник|день\s*рождения/iu.test(text)) score += 5;
    if (/мангал|барбекю|беседк/iu.test(text)) score += 4;
    if (/баня|сауна/iu.test(text)) score += 3;
    if (extractRating(item) !== null) score += 2;

    const sameAsCity = normalize(name) === input.city_normalized && normalize(address) === input.city_normalized;
    return {
      item,
      name,
      address,
      score,
      sameAsCity
    };
  })
  .filter((entry) => !entry.sameAsCity && entry.name);

const sorted = ranked.sort((a, b) => b.score - a.score || String(a.name || '').localeCompare(String(b.name || ''), 'ru'));
const preferred = sorted.filter((entry) => entry.score >= 8);
const selected = (preferred.length > 0 ? preferred : sorted).slice(0, 10);

const dedup = new Set();
const venues = [];
for (const { item, name, address } of selected) {
  const key = `${normalize(name)}|${normalize(address)}`;
  if (dedup.has(key)) continue;
  dedup.add(key);

  venues.push({
    id: item.id || null,
    name,
    image_url: extractImageUrl(item),
    description: extractDescription(item),
    rating: extractRating(item),
    address,
    address_name: toText(item.address_name),
    address_comment: toText(item.address_comment),
    working_hours: formatSchedule(item.schedule),
    avg_bill: extractAvgBill(item),
    cuisine: extractCuisine(item),
    contacts: extractContacts(item),
    purpose_name: toText(item.purpose_name),
    type: toText(item.type)
  });
}

return [
  {
    json: {
      total: venues.length,
      venues,
      debug: {
        original_total: $json.result?.total || 0,
        query_2gis: input.query_2gis,
        housing_terms: input.housing_terms,
        occasion_terms: input.occasion_terms,
        feature_terms: input.feature_terms
      }
    }
  }
];
